namespace sv_166c642149a743a38685dc61c85cbe99.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int PrepTimeMinutes { get; set; }
}

using sv_166c642149a743a38685dc61c85cbe99.Models;

namespace sv_166c642149a743a38685dc61c85cbe99.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Description = "Roman pasta with guanciale, egg yolks, Pecorino Romano, and black pepper.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Risotto alla Milanese", Description = "Creamy saffron-infused risotto from Milan.", PrepTimeMinutes = 40 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Pad Thai", Description = "Stir-fried rice noodles with shrimp, peanuts, bean sprouts, and tamarind sauce.", PrepTimeMinutes = 35 },
            new() { Id = 5, Title = "Green Curry", Description = "Aromatic coconut-based curry with Thai basil, bamboo shoots, and chicken.", PrepTimeMinutes = 45 },
            new() { Id = 6, Title = "Tom Yum Soup", Description = "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", PrepTimeMinutes = 20 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Spit-grilled pork tacos with pineapple, cilantro, and onion on corn tortillas.", PrepTimeMinutes = 50 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime juice, cilantro, jalapeño, and tomato.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Enchiladas Verdes", Description = "Corn tortillas filled with chicken, covered in tangy tomatillo salsa verde.", PrepTimeMinutes = 40 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes.Select(r => new Recipe
            {
                Id = r.Id,
                Title = r.Title,
                Description = r.Description,
                PrepTimeMinutes = r.PrepTimeMinutes,
            }).ToList();
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_166c642149a743a38685dc61c85cbe99.Models
@using sv_166c642149a743a38685dc61c85cbe99.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IAsyncDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (!string.IsNullOrEmpty(Sort))
{
    <p><em>Sorted by: @Sort</em></p>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2" role="status">Refreshing…</div>
    }

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <ul>
            @foreach (var recipe in GetSortedRecipes())
            {
                <li>
                    <strong>@recipe.Title</strong> — @recipe.PrepTimeMinutes min
                    <br />@recipe.Description
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only the sort parameter (or nothing) changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for the previous cuisine.
        await CancelPendingRequestAsync();

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        var targetCuisineId = CuisineId;

        var cts = CancellationTokenSource.CreateLinkedTokenSource(default);
        _cts = cts;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(targetCuisineId, cts.Token);

            // Guard: component may have been disposed or a newer request may have started.
            if (_disposed || cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
            _loadedCuisineId = targetCuisineId;
        }
        catch (OperationCanceledException)
        {
            // Expected when the user navigated away or changed cuisine mid-load.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", targetCuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", targetCuisineId);
            _errorMessage = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
        {
            return new List<Recipe>();
        }

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            _ => _recipes,
        };
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        _disposed = true;
        await CancelPendingRequestAsync();
    }
}

